import { createCanvas } from 'canvas';
import paper from '@chnak/paper';
import { initDefaultFont } from './src/index.js';
import { TextElement } from './src/elements/TextElement.js';
initDefaultFont\(\);

const canvas = createCanvas\(1920, 1080\);
paper.setup\(canvas\);

const config = {
  text: 'Fubuilder',
  x: '50%',
  y: '50%',
  fontSize: 120,
  fontFamily: 'PatuaOne',
  color: '#000000',
  textAlign: 'center',
  anchor: [0.5, 0.5],
  duration: 3,
  startTime: 0,
  split: 'letter',
};

const element = new TextElement\(config\);
const layer = new paper.Layer\(\);

// 手动模拟 render 流程
const seg0 = element.segments[0];
const state = seg0.getStateAtTime\(1.5, { width: 1920, height: 1080, baseFontSize: 16 }\);

// 1. 计算位置
const segmentPos = seg0.calculateSegmentPosition\(state, { width: 1920, height: 1080, baseFontSize: 16 }, {
  parentX: seg0.config.parentX,
  parentY: seg0.config.parentY,
  parentAnchor: seg0.config.parentAnchor,
  parentTextAlign: seg0.config.parentTextAlign,
  totalTextWidth: seg0.config.totalTextWidth,
  totalTextHeight: seg0.config.totalTextHeight,
  segmentOffsetX: seg0.config.segmentOffsetX,
  segmentOffsetY: seg0.config.segmentOffsetY,
}\);

const x = segmentPos.x;
const y = segmentPos.y;

console.log\('x =', x\);

// 2. 创建 PointText
const p = paper;
const pointText = new p.PointText\(new p.Point\(x, y\)\);
pointText.content = 'F';
pointText.fontSize = 120;
pointText.fontFamily = 'PatuaOne';
pointText.fontWeight = 'normal';
pointText.fontStyle = 'normal';
pointText.fillColor = '#000000';
pointText.justification = 'left';

console.log\('创建后 position.x:', pointText.position.x\);
console.log\('创建后 bounds.center:', pointText.bounds.x + pointText.bounds.width/2\);

// 3. 位置对齐
const boundsForAlign = pointText.bounds;
const textW = boundsForAlign.width;
const textH = boundsForAlign.height;
const anchor = state.anchor || [0.5, 0.5];

let finalX = x;
let finalY = y;
if \(anchor[0] === 0.5 && anchor[1] === 0.5\) {
  finalX = x;
  finalY = y;
} else {
  finalX = x + textW * \(0.5 - anchor[0]\);
  finalY = y + textH * \(0.5 - anchor[1]\);
}

pointText.position = new p.Point\(finalX, finalY\);
console.log\('\\\\n位置对齐后 position.x:', pointText.position.x\);
console.log\('位置对齐后 bounds.center:', pointText.bounds.x + pointText.bounds.width/2\);

// 4. applyTransform\(applyPosition=false\)
console.log\('\\\\n调用 applyTransform\(applyPosition=false\)...'\);
seg0.applyTransform\(pointText, state, {
  applyPosition: false,
  paperInstance: { paper },
}\);
console.log\('applyTransform 后 position.x:', pointText.position.x\);
console.log\('applyTransform 后 bounds.center:', pointText.bounds.x + pointText.bounds.width/2\);

// 5. 添加到 layer
layer.addChild\(pointText\);
console.log\('\\\\n添加到 layer 后 position.x:', pointText.position.x\);
console.log\('添加到 layer 后 bounds.center:', pointText.bounds.x + pointText.bounds.width/2\);
")
